import android.content.Context
import android.content.SharedPreferences
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey

class AuthenticationManager private constructor(context: Context) {

    companion object {
        private const val PREFS_FILE_NAME = "auth_secure_prefs"
        private const val KEY_AUTH_TOKEN = "auth_token"
        private const val KEY_USER_ID = "user_id"
        private const val KEY_IS_LOGGED_IN = "is_logged_in"
        private const val KEY_TOKEN_EXPIRY = "token_expiry"

        @Volatile
        private var instance: AuthenticationManager? = null

        fun getInstance(context: Context): AuthenticationManager {
            return instance ?: synchronized(this) {
                instance ?: AuthenticationManager(context.applicationContext).also {
                    instance = it
                }
            }
        }
    }

    private val encryptedPrefs: SharedPreferences

    init {
        val masterKey = MasterKey.Builder(context.applicationContext)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()

        encryptedPrefs = EncryptedSharedPreferences.create(
            context.applicationContext,
            PREFS_FILE_NAME,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    /**
     * Persists authentication state after successful login.
     * Only stores the auth token and user ID — never the password.
     *
     * @param authToken The server-issued authentication token.
     * @param userId The authenticated user's ID.
     * @param tokenExpiryMillis Optional token expiry timestamp in milliseconds since epoch.
     */
    fun saveAuthState(authToken: String, userId: String, tokenExpiryMillis: Long = 0L) {
        require(authToken.isNotBlank()) { "Auth token must not be blank" }
        require(userId.isNotBlank()) { "User ID must not be blank" }

        encryptedPrefs.edit().apply {
            putString(KEY_AUTH_TOKEN, authToken)
            putString(KEY_USER_ID, userId)
            putBoolean(KEY_IS_LOGGED_IN, true)
            if (tokenExpiryMillis > 0L) {
                putLong(KEY_TOKEN_EXPIRY, tokenExpiryMillis)
            }
            apply()
        }
    }

    /**
     * Returns the stored auth token, or null if not logged in or token has expired.
     */
    fun getAuthToken(): String? {
        if (!isLoggedIn()) return null

        if (isTokenExpired()) {
            clearAuthState()
            return null
        }

        return encryptedPrefs.getString(KEY_AUTH_TOKEN, null)
    }

    /**
     * Returns the stored user ID, or null if not logged in.
     */
    fun getUserId(): String? {
        if (!isLoggedIn()) return null
        return encryptedPrefs.getString(KEY_USER_ID, null)
    }

    /**
     * Checks whether the user has a persisted login state.
     */
    fun isLoggedIn(): Boolean {
        return encryptedPrefs.getBoolean(KEY_IS_LOGGED_IN, false)
    }

    /**
     * Checks whether the stored token has expired based on the persisted expiry time.
     */
    fun isTokenExpired(): Boolean {
        val expiry = encryptedPrefs.getLong(KEY_TOKEN_EXPIRY, 0L)
        if (expiry == 0L) return false // No expiry set; treat as non-expiring
        return System.currentTimeMillis() >= expiry
    }

    /**
     * Returns the token expiry timestamp, or 0 if none was set.
     */
    fun getTokenExpiryMillis(): Long {
        return encryptedPrefs.getLong(KEY_TOKEN_EXPIRY, 0L)
    }

    /**
     * Updates only the auth token (e.g., after a token refresh).
     */
    fun updateAuthToken(newAuthToken: String, newExpiryMillis: Long = 0L) {
        require(newAuthToken.isNotBlank()) { "Auth token must not be blank" }
        require(isLoggedIn()) { "Cannot update token when not logged in" }

        encryptedPrefs.edit().apply {
            putString(KEY_AUTH_TOKEN, newAuthToken)
            if (newExpiryMillis > 0L) {
                putLong(KEY_TOKEN_EXPIRY, newExpiryMillis)
            }
            apply()
        }
    }

    /**
     * Clears all persisted authentication data. Call on logout.
     */
    fun clearAuthState() {
        encryptedPrefs.edit().clear().apply()
    }

    /**
     * Convenience data class representing the current auth state.
     */
    data class AuthState(
        val isLoggedIn: Boolean,
        val userId: String?,
        val authToken: String?,
        val tokenExpiryMillis: Long
    )

    /**
     * Returns a snapshot of the current authentication state.
     */
    fun getAuthState(): AuthState {
        return AuthState(
            isLoggedIn = isLoggedIn(),
            userId = getUserId(),
            authToken = getAuthToken(),
            tokenExpiryMillis = getTokenExpiryMillis()
        )
    }
}